// ============================================================================
// SECTION 1: VALIDATE INPUT
// ============================================================================

const body = $input.first().json.body;

const playbookId = body.playbook_id || body.playbookId;
const extractedText = body.extracted_text || body.extractedText || "";

if (!playbookId) {
  throw new Error("Missing required field: playbook_id");
}

if (!extractedText || extractedText.length < 100) {
  throw new Error(
    "Missing or insufficient extracted_text. Length: " +
      (extractedText?.length || 0) +
      ". Text must be extracted client-side before calling this webhook.",
  );
}

return {
  playbookId,
  extractedText,
  extractedTextLength: extractedText.length,
  timestamp: new Date().toISOString(),
};

// ============================================================================
// SMART PLAYBOOK EXTRACTION - Aligned to actual playbook_rules schema
// V5: Rule count fix, range differentiation, provider perspective support
// ============================================================================

const playbookData = $("Get Playbook Metadata").first().json;

// Read extracted text from Validate Input (sent by frontend)
const validateData = $("Validate Input").first().json;
const extractedText = validateData.extractedText || "";

if (!extractedText || extractedText.length < 100) {
  throw new Error(
    "No usable text received from frontend extraction. Length: " +
      (extractedText?.length || 0),
  );
}

// ============================================================================
// PLAYBOOK PERSPECTIVE — customer or provider?
// ============================================================================
// Determines how positions are interpreted. If the playbook was uploaded by
// a provider company, the positions represent the provider's goals (lower
// numbers = stronger provider position). If customer, higher = stronger.

const perspective = playbookData.playbook_perspective || "customer";

// ============================================================================
// SMART EXTRACTION: Find and keep sections with negotiation rules
// ============================================================================
// Set to 80K: large enough to capture most playbooks in full, while the
// reduced output fields (dropped talking_points, common_objections,
// counter_arguments) keep total response within timeout.

const MAX_CHARS = 80000;
const originalLength = extractedText.length;

let processedText = extractedText;
let wasTruncated = false;
let extractionMethod = "full";

if (extractedText.length > MAX_CHARS) {
  wasTruncated = true;

  const importantKeywords = [
    "position",
    "limit",
    "threshold",
    "escalat",
    "approv",
    "accept",
    "red line",
    "redline",
    "non-negotiable",
    "mandatory",
    "must not",
    "minimum",
    "maximum",
    "range",
    "cap",
    "ceiling",
    "floor",
    "liability",
    "indemnit",
    "warrant",
    "terminat",
    "payment",
    "intellectual property",
    "confidential",
    "data protection",
    "service level",
    "sla",
    "penalty",
    "breach",
    "remedy",
    "insurance",
    "force majeure",
    "governance",
    "audit",
    "preferred",
    "ideal",
    "fallback",
    "walk away",
    "deal breaker",
    "negotiate",
    "concession",
    "trade-off",
    "compromise",
    "employment",
    "tupe",
    "benchmarking",
    "change control",
    "dispute",
    "exit",
    "transition",
    "subcontract",
  ];

  const sections = extractedText.split(/\n{2,}|\r\n{2,}/);

  const scoredSections = sections.map((section, index) => {
    const lowerSection = section.toLowerCase();
    let score = 0;
    importantKeywords.forEach((keyword) => {
      if (lowerSection.includes(keyword.toLowerCase())) score += 2;
    });
    if (
      /\d+%|\$[\d,]+|£[\d,]+|€[\d,]+|\d+\s*(days|months|years|hours)/i.test(
        section,
      )
    )
      score += 3;
    if (/position\s*[:\-]?\s*\d/i.test(section)) score += 5;
    if (/^[\d\.]+\s+[A-Z]|^[A-Z][a-z]+\s+[A-Z][a-z]+\s*:/m.test(section))
      score += 2;
    if (index < 10) score += 1;
    return { section, score, index };
  });

  const sortedSections = scoredSections
    .filter((s) => s.section.trim().length > 50)
    .sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      return a.index - b.index;
    });

  let currentLength = 0;
  const selectedSections = [];

  const introSections = scoredSections.slice(0, 5).map((s) => s.section);
  introSections.forEach((s) => {
    selectedSections.push(s);
    currentLength += s.length;
  });

  for (const item of sortedSections) {
    if (currentLength + item.section.length > MAX_CHARS - 1000) break;
    if (!selectedSections.includes(item.section)) {
      selectedSections.push(item.section);
      currentLength += item.section.length;
    }
  }

  const sectionOrderMap = new Map(scoredSections.map((s, i) => [s.section, i]));
  selectedSections.sort(
    (a, b) => (sectionOrderMap.get(a) || 0) - (sectionOrderMap.get(b) || 0),
  );

  processedText = selectedSections.join("\n\n");
  extractionMethod = "smart_keyword";

  processedText += `\n\n[SMART EXTRACTION: Selected ${selectedSections.length} of ${sections.length} sections based on relevance. Original: ${originalLength} chars, Processed: ${processedText.length} chars]`;
}

// ============================================================================
// Build perspective-aware scale definition
// ============================================================================

const scaleDefinition =
  perspective === "provider"
    ? `═══════════════════════════════════════════════════
POSITION SCALE (1-10) — PROVIDER PERSPECTIVE
═══════════════════════════════════════════════════

THIS IS A PROVIDER/SUPPLIER PLAYBOOK. Positions represent what the PROVIDER wants.

Position 1  = Weakest position for this provider (maximum concession to customer)
Position 5  = Balanced / Market standard
Position 10 = Strongest position for this provider (maximum protection for provider)

The scale is oriented so that:
- Higher number = MORE favourable for the PROVIDER (supplier, vendor)
- Lower number  = MORE concession to the CUSTOMER (buyer, tenant)

Example: A provider wanting long payment terms (90 days) would set ideal_position HIGH (8-9).
A provider accepting short payment terms (7 days) would set minimum_position LOW (2-3).`
    : `═══════════════════════════════════════════════════
POSITION SCALE (1-10) — CUSTOMER PERSPECTIVE
═══════════════════════════════════════════════════

THIS IS A CUSTOMER/BUYER PLAYBOOK. Positions represent what the CUSTOMER wants.

Position 1  = Maximum flexibility for the PROVIDING party (supplier, vendor, landlord, licensor)
Position 5  = Balanced / Market standard
Position 10 = Maximum protection for the PROTECTED party (customer, tenant, buyer, licensee)

The scale is oriented so that:
- Higher number = MORE protection for the customer/buyer
- Lower number  = MORE flexibility for the supplier/provider

Example: A customer wanting short payment terms (7 days) would set ideal_position HIGH (8-9).
A customer accepting long payment terms (90 days) would set minimum_position LOW (2-3).`;

// ============================================================================
// PROMPT V5 — Perspective-aware, range-differentiated, output-optimised
// ============================================================================

const systemPrompt = `You are an expert at extracting negotiation rules from corporate contract playbooks.

CRITICAL INSTRUCTION: You MUST extract EVERY negotiation rule, position, red line, escalation trigger, and policy directive from the document. Do NOT summarise, consolidate, or skip rules. A large corporate playbook may contain 80-150+ rules. If you extract fewer than 30, you have almost certainly missed rules.

${scaleDefinition}

═══════════════════════════════════════════════════
FOUR POSITION VALUES PER RULE
═══════════════════════════════════════════════════

- ideal_position: The company's PREFERRED opening position (where they want to start).
- minimum_position: The absolute FLOOR. Below this is unacceptable.
- maximum_position: Best case / aspirational ceiling.
- fallback_position: Compromise if ideal is rejected. Between minimum and ideal.

RULES:
- minimum_position <= fallback_position <= ideal_position <= maximum_position
- All four values MUST be different from each other when the playbook provides enough context.
- Use the FULL 1-10 range. Do not cluster everything around 5-6.

═══════════════════════════════════════════════════
CRITICAL — EVERY RULE MUST HAVE UNIQUE POSITIONS
═══════════════════════════════════════════════════

WRONG — identical positions across rules in a category:
  "Liability Cap":       ideal=8, min=6, max=10, fallback=7
  "Consequential Loss":  ideal=8, min=6, max=10, fallback=7  ← WRONG: copied
  "Indemnity Scope":     ideal=8, min=6, max=10, fallback=7  ← WRONG: copied

RIGHT — each rule reflects its SPECIFIC playbook guidance:
  "Liability Cap":       ideal=8, min=5, max=10, fallback=7  (% of fees — cap at 150%)
  "Consequential Loss":  ideal=9, min=7, max=10, fallback=8  (scope — must exclude)
  "Indemnity Scope":     ideal=7, min=4, max=9,  fallback=6  (scope — IP indemnity only)

Every clause deals with a DIFFERENT aspect — even within the same category. Read the playbook text for EACH clause and assign positions based on what IT says, not what the category says.

Each clause also has its OWN unit of measurement:
- "Liability Cap" → % of fees
- "Consequential Loss" → scope (broad to narrow)
- "Indemnity Period" → months
- "Service Credits" → % of monthly charges
Do NOT apply one measure to all clauses in a section.

═══════════════════════════════════════════════════
CATEGORY MEASURE GUIDE
═══════════════════════════════════════════════════

Use the correct unit for each clause. Override when the clause clearly deals with something different.

liability: % of annual fees (caps), scope (exclusions), months (indemnity periods)
payment: days (terms), % (interest rates), days (dispute windows)
termination: months (notice), scope (rights), days (cure periods)
confidentiality: years (duration), scope (definition breadth)
service_levels: % uptime, % monthly charges (credits), scope (remedies)
insurance: GBP/USD coverage amounts
data_protection: hours (breach notification), scope (audit rights), days (data return)
intellectual_property: years (licence), scope (ownership)

═══════════════════════════════════════════════════
RANGE CONTEXT — REQUIRED FOR EACH RULE
═══════════════════════════════════════════════════

"range_context": {
  "value_type": "duration" | "percentage" | "currency" | "count" | "boolean" | "text",
  "range_unit": "<e.g. '% of annual fees', 'months notice', 'GBP', 'days'>",
  "scale_points": [
    { "position": 1, "label": "<value at pos 1>", "value": <number> },
    { "position": 5, "label": "<value at pos 5>", "value": <number> },
    { "position": 10, "label": "<value at pos 10>", "value": <number> }
  ],
  "source": "parsed"
}

- EXACTLY 3 scale_points: positions 1, 5, and 10.
- Each rule's range_context MUST match THAT rule's unit, not the category default.
- For qualitative clauses, use value_type "text" and descriptive labels.

═══════════════════════════════════════════════════
OTHER FIELDS — KEEP TEXT SHORT (max 12 words)
═══════════════════════════════════════════════════

- clause_code: Short ID (e.g. "LIA-001", "TERM-002")
- clause_name: Specific title (e.g. "Liability Cap", not just "Liability")
- category: One of: liability, termination, payment, intellectual_property, confidentiality, data_protection, service_levels, warranties, indemnification, insurance, governance, employment, audit, benchmarking, dispute_resolution, change_control, exit_transition, subcontracting, force_majeure, other
- rationale: Why this matters (max 12 words)
- negotiation_tips: Key tactic (max 12 words)
- escalation_trigger: What triggers escalation (max 12 words, or null)
- escalation_contact: Role to escalate to (e.g. "Legal Director")
- requires_approval_below: Position needing approval (integer 1-10, or null)
- importance_level: Criticality 1-10
- is_deal_breaker: true if walking away is required when breached
- is_non_negotiable: true if position cannot change at all

═══════════════════════════════════════════════════
QUALITY CHECKS — VERIFY BEFORE RETURNING
═══════════════════════════════════════════════════

1. DIFFERENTIATION: Scan your output. If ANY 2 rules in the same category share the SAME ideal_position AND minimum_position, go back and fix them. Each rule MUST have unique position values.
2. FULL RANGE: Across all rules, positions should span at least 3 to 9.
3. CORRECT MEASURES: Each rule's range_context.range_unit must match THAT clause's unit.
4. POSITION ORDER: minimum <= fallback <= ideal <= maximum for every rule.
5. COMPLETENESS: Count your rules. This playbook may contain 80-150 rules. Extract ALL of them.

IMPORTANT OUTPUT RULES:
1. Number clause_codes sequentially within each category
2. Return ONLY valid JSON, no markdown backticks

{
  "playbook_summary": "...",
  "playbook_perspective": "${perspective}",
  "extraction_confidence": 0.85,
  "total_rules_extracted": 45,
  "rules": [{ ... }]
}`;

const userPrompt = `Extract ALL negotiation rules from this ${perspective === "provider" ? "PROVIDER" : "CUSTOMER"} playbook. Be thorough — extract every rule, red line, position directive, escalation trigger, and approval threshold.

This playbook is written from the ${perspective === "provider" ? "PROVIDER/SUPPLIER" : "CUSTOMER/BUYER"} perspective. Position values should reflect what the ${perspective === "provider" ? "provider" : "customer"} wants.

IMPORTANT: Each clause MUST have its own unique position values and unit of measurement. Do NOT copy positions across clauses in the same category.

PLAYBOOK: ${playbookData.playbook_name}
${wasTruncated ? `[Note: Key sections extracted via ${extractionMethod}. Focus on extracting rules from ALL sections provided.]` : ""}

---
${processedText}
---

Extract EVERY rule with unique positions and per-clause range_context. Count them — aim for completeness. Keep text fields under 12 words. Return ONLY the JSON object.`;

return {
  playbookId: playbookData.playbook_id,
  companyId: playbookData.company_id,
  playbookName: playbookData.playbook_name,
  perspective,
  systemPrompt,
  userPrompt,
  originalLength,
  processedLength: processedText.length,
  wasTruncated,
  extractionMethod,
};

// ============================================================================
// PROCESS CLAUDE RESPONSE — Pass 1 JSON parser with truncation recovery
// Location: n8n-workflows/process-claude-response.js
//
// Sits between the Claude API node and Validate Extracted Rules.
// Handles the case where Claude's response is truncated mid-JSON (common on
// large documents that push against the output token limit).
//
// Copy this code into the n8n "Process Claude Response" Code node.
// ============================================================================

const input = $input.first().json;

// Claude API node returns the response in different shapes depending on version
const rawContent =
  input?.message?.content?.[0]?.text ||
  input?.content?.[0]?.text ||
  input?.text ||
  input?.response ||
  "";

if (!rawContent) {
  throw new Error("No content received from Claude API node");
}

// ============================================================================
// STEP 1: Strip markdown fences if Claude wrapped the JSON anyway
// ============================================================================

let jsonStr = rawContent.trim();
if (jsonStr.startsWith("```")) {
  jsonStr = jsonStr
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/```\s*$/, "")
    .trim();
}

// ============================================================================
// STEP 2: Attempt clean parse first
// ============================================================================

let parsed = null;
let wasTruncated = false;

try {
  parsed = JSON.parse(jsonStr);
} catch (firstError) {
  // ============================================================================
  // STEP 3: Truncation recovery
  //
  // Claude truncates mid-string inside the rules array. We try to salvage
  // every rule object that completed before the cut-off.
  //
  // The Claude prompt instructs Claude to use "rules" as the array key.
  // We also check "clause_inventory" as a legacy fallback.
  //
  // Strategy A — depth tracking (fast, accurate):
  //   Walk forward tracking brace depth; record every position where a
  //   top-level rule object closes (depth returns to 0). Use the last such
  //   position as the safe cut-off point.
  //
  // Strategy B — backward scan (resilient fallback):
  //   If Strategy A finds nothing (truncation hit the very first rule, or a
  //   string-skipping edge case threw the depth counter off), walk backward
  //   through every '}' in the rules section and attempt JSON.parse on each
  //   candidate reconstruction until one succeeds.
  // ============================================================================

  wasTruncated = true;
  let recovered = false;

  // The prompt uses "rules" as the array key; "clause_inventory" is a legacy fallback
  const arrayKey = jsonStr.includes('"rules"') ? '"rules"' : '"clause_inventory"';

  const arrayStart = jsonStr.indexOf(arrayKey);
  if (arrayStart !== -1) {
    const bracketOpen = jsonStr.indexOf("[", arrayStart);
    if (bracketOpen !== -1) {
      const headerStr = jsonStr.slice(0, bracketOpen + 1); // up to and including '['

      // ---- Strategy A: forward depth-tracking scan -------------------------
      let depth = 0;
      let lastCompleteRuleEnd = -1;

      for (let i = bracketOpen + 1; i < jsonStr.length; i++) {
        const ch = jsonStr[i];
        // Skip over string literals — they may contain braces that would
        // corrupt the depth counter
        if (ch === '"') {
          i++;
          while (i < jsonStr.length) {
            if (jsonStr[i] === "\\") {
              i += 2; // skip escaped character (handles \" correctly)
              continue;
            }
            if (jsonStr[i] === '"') break;
            i++;
          }
          continue;
        }
        if (ch === "{") depth++;
        if (ch === "}") {
          depth--;
          if (depth === 0) {
            lastCompleteRuleEnd = i;
          }
        }
      }

      if (lastCompleteRuleEnd !== -1) {
        const rulesStr = jsonStr.slice(bracketOpen + 1, lastCompleteRuleEnd + 1);
        const reconstructed = headerStr + rulesStr + "]}";
        try {
          parsed = JSON.parse(reconstructed);
          recovered = true;
          parsed.playbook_summary = parsed.playbook_summary || null;
          parsed.extraction_confidence = parsed.extraction_confidence || null;
          const ruleArray = parsed.rules || parsed.clause_inventory || [];
          parsed.total_rules_extracted = ruleArray.length;
          parsed._truncation_recovered = true;
          parsed._recovery_strategy = "depth-tracking";
          parsed._original_error = firstError.message;
        } catch (_strategyAParseError) {
          // Boundary looked right but reconstruction is still malformed —
          // fall through to Strategy B
        }
      }

      // ---- Strategy B: backward scan through all '}' positions -------------
      if (!recovered) {
        const closingBraces = [];
        for (let i = bracketOpen + 1; i < jsonStr.length; i++) {
          if (jsonStr[i] === "}") closingBraces.push(i);
        }

        // Try from the rightmost '}' leftward — we typically succeed within
        // the first few iterations (the truncation is near the end)
        for (let idx = closingBraces.length - 1; idx >= 0 && !recovered; idx--) {
          const cutoff = closingBraces[idx];
          const rulesStr = jsonStr.slice(bracketOpen + 1, cutoff + 1);
          const reconstructed = headerStr + rulesStr + "]}";
          try {
            parsed = JSON.parse(reconstructed);
            recovered = true;
            parsed.playbook_summary = parsed.playbook_summary || null;
            parsed.extraction_confidence = parsed.extraction_confidence || null;
            const ruleArray = parsed.rules || parsed.clause_inventory || [];
            parsed.total_rules_extracted = ruleArray.length;
            parsed._truncation_recovered = true;
            parsed._recovery_strategy = "backward-scan";
            parsed._original_error = firstError.message;
          } catch (_strategyBParseError) {
            // Keep scanning leftward
          }
        }
      }
    }
  }

  if (!recovered) {
    throw new Error(
      `Failed to parse Claude response and truncation recovery failed.\n` +
      `Original error: ${firstError.message}\n` +
      `Response length: ${rawContent.length} chars\n` +
      `Array key found: ${jsonStr.includes('"rules"') ? '"rules"' : jsonStr.includes('"clause_inventory"') ? '"clause_inventory"' : 'neither'}\n` +
      `Tip: increase max_tokens on the Claude node, or reduce document size.`
    );
  }
}

// ============================================================================
// STEP 4: Normalise output
// ============================================================================

// Claude prompt uses "rules"; "clause_inventory" kept as legacy fallback
const rules = parsed.rules || parsed.clause_inventory || [];

if (rules.length === 0) {
  throw new Error(
    "Claude returned 0 rules. The document may be too short, in an unsupported " +
    "format, or the response was truncated before any rules were extracted."
  );
}

// The Claude HTTP node only returns the API response body — context fields
// (playbookId, companyId, playbookName) were set in Prepare Claude Prompt.
const prepareData = $('Prepare Claude Prompt').first().json;

return {
  playbookId: prepareData.playbookId || null,
  companyId: prepareData.companyId || null,
  playbookName: prepareData.playbookName || null,
  perspective: parsed.playbook_perspective || prepareData.perspective || "customer",
  playbook_summary: parsed.playbook_summary || null,
  extraction_confidence: parsed.extraction_confidence || null,
  total_rules_extracted: rules.length,
  rules,
  extractedText: prepareData.extractedText || "",
  // Diagnostic fields
  wasTruncated,
  truncationRecovered: parsed._truncation_recovered || false,
  recoveryStrategy: parsed._recovery_strategy || null,
  originalParseError: parsed._original_error || null,
};

// ============================================================================
// VALIDATE PLAYBOOK RULES — Post-extraction quality checks
// Location: n8n-workflows/validate-playbook-rules.js
//
// Runs AFTER Process Claude Response, BEFORE Split Into Rules.
// Adds quality_flags to each rule and sets hasQualityIssues flag.
//
// Copy this code into the n8n "Validate Extracted Rules" Code node.
// ============================================================================

const input = $input.first().json;
const rules = input.rules || [];

// ============================================================================
// VALIDATION CHECKS
// ============================================================================

// Group rules by normalised category
const categoryGroups = {};
for (const rule of rules) {
  const cat = (rule.category || "general").toLowerCase().trim();
  if (!categoryGroups[cat]) categoryGroups[cat] = [];
  categoryGroups[cat].push(rule);
}

for (const rule of rules) {
  if (!rule.quality_flags) rule.quality_flags = [];
  // Parse quality_flags if it's a string (from prior step)
  if (typeof rule.quality_flags === "string") {
    try {
      rule.quality_flags = JSON.parse(rule.quality_flags);
    } catch {
      rule.quality_flags = [];
    }
  }
}

// --------------------------------------------------------------------------
// CHECK 1: Duplicate range_unit + scale_points within same category
// --------------------------------------------------------------------------
for (const [cat, catRules] of Object.entries(categoryGroups)) {
  for (let i = 0; i < catRules.length; i++) {
    for (let j = i + 1; j < catRules.length; j++) {
      const riCtx =
        typeof catRules[i].range_context === "string"
          ? JSON.parse(catRules[i].range_context || "{}")
          : catRules[i].range_context;
      const rjCtx =
        typeof catRules[j].range_context === "string"
          ? JSON.parse(catRules[j].range_context || "{}")
          : catRules[j].range_context;

      if (!riCtx || !rjCtx) continue;

      const iLabels = (riCtx.scale_points || [])
        .map((sp) => sp.label)
        .join("|");
      const jLabels = (rjCtx.scale_points || [])
        .map((sp) => sp.label)
        .join("|");

      if (
        riCtx.range_unit === rjCtx.range_unit &&
        iLabels === jLabels &&
        iLabels.length > 0
      ) {
        if (!catRules[i].quality_flags.includes("duplicate_range_in_category"))
          catRules[i].quality_flags.push("duplicate_range_in_category");
        if (!catRules[j].quality_flags.includes("duplicate_range_in_category"))
          catRules[j].quality_flags.push("duplicate_range_in_category");
      }
    }
  }
}

// --------------------------------------------------------------------------
// CHECK 2: Mixed value types within a single rule's scale_points
// --------------------------------------------------------------------------
for (const rule of rules) {
  const ctx =
    typeof rule.range_context === "string"
      ? JSON.parse(rule.range_context || "{}")
      : rule.range_context;

  if (!ctx?.scale_points?.length) {
    if (!rule.quality_flags.includes("missing_range_context"))
      rule.quality_flags.push("missing_range_context");
    continue;
  }

  const labels = ctx.scale_points.map((sp) => (sp.label || "").toLowerCase());
  const hasPercentage = labels.some((l) => l.includes("%"));
  const hasDuration = labels.some((l) =>
    /year|month|day|week|hour|perpetual|indefinite/i.test(l),
  );
  const hasCurrency = labels.some((l) => /\$|£|€|gbp|usd|eur/i.test(l));
  const typeCount = [hasPercentage, hasDuration, hasCurrency].filter(
    Boolean,
  ).length;

  if (typeCount > 1) {
    if (!rule.quality_flags.includes("mixed_value_types"))
      rule.quality_flags.push("mixed_value_types");
  }
}

// --------------------------------------------------------------------------
// CHECK 3: Duplicate positions within same category
// --------------------------------------------------------------------------
for (const [cat, catRules] of Object.entries(categoryGroups)) {
  for (let i = 0; i < catRules.length; i++) {
    for (let j = i + 1; j < catRules.length; j++) {
      if (
        catRules[i].ideal_position === catRules[j].ideal_position &&
        catRules[i].minimum_position === catRules[j].minimum_position &&
        catRules[i].maximum_position === catRules[j].maximum_position
      ) {
        if (
          !catRules[i].quality_flags.includes("duplicate_positions_in_category")
        )
          catRules[i].quality_flags.push("duplicate_positions_in_category");
        if (
          !catRules[j].quality_flags.includes("duplicate_positions_in_category")
        )
          catRules[j].quality_flags.push("duplicate_positions_in_category");
      }
    }
  }
}

// --------------------------------------------------------------------------
// CHECK 4: Nonsensical scale progression (position 1 label > position 10)
// --------------------------------------------------------------------------
for (const rule of rules) {
  const ctx =
    typeof rule.range_context === "string"
      ? JSON.parse(rule.range_context || "{}")
      : rule.range_context;

  if (!ctx?.scale_points?.length) continue;

  const sorted = [...ctx.scale_points].sort((a, b) => a.position - b.position);
  const values = sorted.map((sp) => sp.value).filter((v) => v != null);

  if (values.length >= 2) {
    // Check monotonic progression
    let nonMonotonic = false;
    for (let k = 1; k < values.length; k++) {
      if (values[k] < values[k - 1]) {
        nonMonotonic = true;
        break;
      }
    }
    // Note: some scales are intentionally descending (e.g., payment days: 90→7)
    // So only flag if it's neither monotonically increasing nor decreasing
    if (nonMonotonic) {
      let allDescending = true;
      for (let k = 1; k < values.length; k++) {
        if (values[k] > values[k - 1]) {
          allDescending = false;
          break;
        }
      }
      if (!allDescending) {
        if (!rule.quality_flags.includes("non_monotonic_scale"))
          rule.quality_flags.push("non_monotonic_scale");
      }
    }
  }
}

// ============================================================================
// STRINGIFY quality_flags + range_context for SQL insertion
// Stamp playbook_id onto each rule so Insert Rule can access it via $json.playbook_id
// ============================================================================
const playbookId = input.playbookId || null;

// Assign display_order sequentially within each category (1-based, sorted by clause_code)
const categoryOrder = {};
const sortedForOrder = [...rules].sort((a, b) =>
  (a.clause_code || '').localeCompare(b.clause_code || '')
);
for (const rule of sortedForOrder) {
  const cat = (rule.category || 'general').toLowerCase().trim();
  categoryOrder[cat] = (categoryOrder[cat] || 0) + 1;
  rule.display_order = categoryOrder[cat];
}

for (const rule of rules) {
  rule.playbook_id = playbookId;
  rule.quality_flags = JSON.stringify(rule.quality_flags || []);
  if (rule.range_context && typeof rule.range_context !== 'string') {
    rule.range_context = JSON.stringify(rule.range_context);
  }
}

// ============================================================================
// SUMMARY
// ============================================================================
const flaggedRules = rules.filter((r) => {
  const flags = JSON.parse(r.quality_flags || "[]");
  return flags.length > 0;
});

const hasQualityIssues = flaggedRules.length > 0;

const flagSummary = {};
for (const rule of rules) {
  const flags = JSON.parse(rule.quality_flags || "[]");
  for (const flag of flags) {
    flagSummary[flag] = (flagSummary[flag] || 0) + 1;
  }
}

return {
  ...input,
  rules,
  hasQualityIssues,
  flaggedRuleCount: flaggedRules.length,
  flagSummary,
};

